import { MakeLogicType, actions, afterMount, kea, listeners, path, reducers } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'

export type MessageCategory = {
    id: string
    key: string
    name: string
    description: string
    public_description: string
    category_type: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface optOutCategoriesLogicValues {
    categories: MessageCategory[]
    categoriesLoading: boolean
    isNewCategoryModalOpen: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface optOutCategoriesLogicActions {
    closeNewCategoryModal: () => {
        value: true
    }
    deleteCategory: (id: string) => {
        id: string
    }
    loadCategories: () => {
        value: true
    }
    loadCategoriesFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadCategoriesSuccess: (
        categories: MessageCategory[],
        payload?: {
            value: true
        }
    ) => {
        categories: MessageCategory[]
        payload?: {
            value: true
        }
    }
    openNewCategoryModal: () => {
        value: true
    }
}

export type optOutCategoriesLogicType = MakeLogicType<optOutCategoriesLogicValues, optOutCategoriesLogicActions>

export const optOutCategoriesLogic = kea<optOutCategoriesLogicType>([
    path(['products', 'workflows', 'frontend', 'OptOuts', 'optOutCategoriesLogic']),

    actions({
        loadCategories: true,
        deleteCategory: (id: string) => ({ id }),
        openNewCategoryModal: true,
        closeNewCategoryModal: true,
    }),

    loaders({
        categories: {
            __default: [] as MessageCategory[],
            loadCategories: async (): Promise<MessageCategory[]> => {
                const response = await api.messaging.getCategories({ category_type: 'marketing' })
                return response.results || []
            },
        },
    }),

    reducers({
        categories: [
            [] as MessageCategory[],
            {
                loadCategoriesSuccess: (_, { categories }) => categories,
            },
        ],
        isNewCategoryModalOpen: [
            false,
            {
                openNewCategoryModal: () => true,
                closeNewCategoryModal: () => false,
            },
        ],
    }),

    listeners(({ actions }) => ({
        deleteCategory: async ({ id }: { id: string }) => {
            try {
                await api.messaging.updateCategory(id, { deleted: true })
                actions.loadCategories()
            } catch (error) {
                console.error('Failed to delete category:', error)
            }
        },
    })),

    afterMount(({ actions }) => {
        actions.loadCategories()
    }),
])
